void fsl_wflow_fifo_reg_16::do_reset()
{
  i_clk = 0;
  i_rstb = 0;
  i_arcfg = 0;
  i_wr_valid = 0;
  i_wr_data = 0;
  i_rd_ready = 0;
  sig_ssa_fifo__wptr = 0;
  sig_ssa_fifo__rptr = 0;
  sig_ssa_fifo__cnt = 0;
  for (int i = 0; i < 19; ++i) sig_ssa_fifo[i] = 0;
  old_ssa_saved_ = false;
  eval_comb();
}
